text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "최종 공개 릴리스 목표는 스모크 테스트 통과를 전제로 금요일 15:00 KST로 확정."
      },
      {
        "item": "smoke-theme-pack.mjs의 packageName 불일치 대응은 스크립트를 즉시 완화하지 않고, 먼저 패키지 설정을 점검한다."
      },
      {
        "item": "packageName 불일치 관련 검토는 계약 자체가 잘못된 경우에 한해 스크립트 변경을 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara 제안: smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경 — 반려됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 가능성 제안(Seoyeon 제안)은 내부 스트레치 목표로만 간주, 최종 마일스톤으로 채택되지 않음."
      }
    ],
    "risks": [
      {
        "item": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "item": "README 설치 가이드가 구식이면 릴리스 노트/안내가 사용자에게 오도될 수 있음."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인지 미확정."
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 미결정."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 리뷰는 목요일에 가능하면 진행 제안만 있었고, 최종 책임자/범위/확정 마감일은 미정."
      },
      {
        "item": "Hara의 tarball 경로 확인은 Minjun의 스모크 결과 공유 후 진행되며, 절대 기한이 명시되지 않음."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성 tarball 경로를 확인한다.",
      "due": "Minjun 결과 게시 후(명시적 시간 미지정)",
      "status": "조건부 확정",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가급적 목요일).",
      "due": "목요일(가능한 경우) — 정확한 기한 미지정",
      "status": "미확정",
      "source_certainty": "중간"
    },
    {
      "owner": "미확정",
      "task": "최종 릴리스 승인권자 확인 및 릴리스 노트에 수요일 스트레치 목표 표기 여부 결정.",
      "due": "추후 확인",
      "status": "열린 항목",
      "source_certainty": "낮음"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 결과가 공유되었는지 확인.",
      "스모크 결과 기반으로 Doyun의 실패 트리아지 노트가 금요일 12:00 KST까지 완료되었는지 확인.",
      "Hara가 tarball 경로 점검을 완료했는지 확인(결과 공유 요청).",
      "packageName mismatch 이슈 발생 시, 패키지 설정 검증 우선 절차가 적용되었는지 확인.",
      "최종 릴리스 승인권자와 릴리스 노트의 스트레치 목표 표기 여부를 확정."
    ],
    "what_not_to_invent": [
      "고객명, 예산, 보안 이슈, 장애, 법무 승인, 소유권/추가 책임자, 마감일(미기재 항목)에 대해 추정·추가 서술 금지.",
      "미확정 항목을 확정사항으로 전환해 서술 금지(예: 최종 승인권자, README 담당자, Hara 마감일)."
    ]
  },
  "non_invention_rules": [
    "명시되지 않은 정보(고객, 예산, 보안 사고, 운영 장애, 법적 승인 요구)는 절대 생성하지 않는다.",
    "회의록에 없는 담당자/소유주를 임의로 발명하지 않는다.",
    "지정되지 않은 기한을 구체 날짜/시간으로 임의 창안하지 않는다.",
    "내부 제안과 최종 결정은 구분해 기록한다.",
    "확정 항목은 ‘확정’, 반려 항목은 ‘반려’, 미결 항목은 ‘열린 질문/비결정’으로 분리해 기록한다.",
    "원문 근거가 없는 목표·지표·KPI·비용/리스크 수치 등을 유추하지 않는다."
  ]
}
